// Validation Logic Tool - Resume Metadata Validator
// Validates resume metadata completeness and quality

const resumeMetadata = query;

// Initialize validation result
const validationResult = {
  isValid: true,
  missingFields: [],
  qualityScore: 100,
  warnings: []
};

// Check required fields
const requiredFields = ['name', 'email', 'skills', 'experience'];

for (const field of requiredFields) {
  if (!resumeMetadata[field] || 
      (Array.isArray(resumeMetadata[field]) && resumeMetadata[field].length === 0) ||
      (typeof resumeMetadata[field] === 'string' && resumeMetadata[field].trim() === '')) {
    validationResult.missingFields.push(field);
    validationResult.isValid = false;
    validationResult.qualityScore -= 25;
  }
}

// Validate email format
if (resumeMetadata.email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(resumeMetadata.email)) {
    validationResult.warnings.push('Invalid email format');
    validationResult.qualityScore -= 10;
  }
} else {
  validationResult.warnings.push('Email is missing');
}

// Validate minimum experience years
if (resumeMetadata.experience !== undefined) {
  const experienceYears = Array.isArray(resumeMetadata.experience) 
    ? resumeMetadata.experience.length 
    : (typeof resumeMetadata.experience === 'number' ? resumeMetadata.experience : 0);

  if (experienceYears < 0) {
    validationResult.warnings.push('Experience years cannot be negative');
    validationResult.qualityScore -= 15;
  }
} else {
  validationResult.warnings.push('Experience data is missing');
}

// Check skill count
if (resumeMetadata.skills) {
  const skillCount = Array.isArray(resumeMetadata.skills) 
    ? resumeMetadata.skills.length 
    : 0;

  if (skillCount === 0) {
    validationResult.warnings.push('No skills listed');
    validationResult.qualityScore -= 20;
  } else if (skillCount < 3) {
    validationResult.warnings.push('Very few skills listed (less than 3)');
    validationResult.qualityScore -= 10;
  }
} else {
  validationResult.warnings.push('Skills data is missing');
}

// Ensure quality score doesn't go below 0
validationResult.qualityScore = Math.max(0, validationResult.qualityScore);

// Return validation result as JSON string
return JSON.stringify(validationResult, null, 2);

